#include <stdio.h>
#include <stdlib.h>
#define MAX 100001
int n, m;
int *low, *num, *stack;
int *edges[MAX];
int scc, idx;
void dfs(int u) {
    static int stackSize = 0;
    num[u] = low[u] = idx++;
    stack[stackSize++] = u;
    for (int i = 0; i < edges[u][0]; i++) {
        int v = edges[u][i + 1];
        if (num[v] == -1) {
            dfs(v);
            low[u] = (low[u] < low[v]) ? low[u] : low[v];
        } else if (stack[stackSize - 1] != v) {
            low[u] = (low[u] < num[v]) ? low[u] : num[v];
        }
    }
    if (low[u] == num[u]) {
        while (1) {
            int v = stack[--stackSize];
            // printf("%d", v);
            if (v == u) break;
        }
        scc++;
    }
}
int main() {
    scanf("%d %d", &n, &m);
    low = (int *)malloc(n * sizeof(int));
    num = (int *)malloc(n * sizeof(int));
    stack = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        edges[i] = (int *)malloc(2 * sizeof(int));
        edges[i][0] = 0;
        num[i] = -1;
    }
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--;
        v--;
        edges[u][0]++;
        edges[u] = (int *)realloc(edges[u], (edges[u][0] + 1) * sizeof(int));
        edges[u][edges[u][0]] = v;
    }
    for (int i = 0; i < n; i++) {
        if (num[i] == -1) dfs(i);
    }
    printf("%d\n", scc);
    return 0;
}

