import java.util.Scanner;
import java.util.ArrayList;
public class Main {
    static final int MAX = 100001;
    static int n, m;
    static int[] low = new int[MAX];
    static int[] num = new int[MAX];
    static int[] stack = new int[MAX];
    static ArrayList<Integer>[] edges = new ArrayList[MAX];
    static int scc, idx;
    public static void dfs(int u) {
        int stackSize = 0;
        num[u] = low[u] = idx++;
        stack[stackSize++] = u;
        for (int v : edges[u]) {
            if (num[v] == -1) {
                dfs(v);
                low[u] = Math.min(low[u], low[v]);
            } else if (stack[stackSize - 1] != v) {
                low[u] = Math.min(low[u], num[v]);
            }
        }
        if (low[u] == num[u]) {
            while (true) {
                int v = stack[--stackSize];
                if (v == u) break;
            }
            scc++;
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        n = scanner.nextInt();
        m = scanner.nextInt();
        for (int i = 0; i < n; i++) {
            num[i] = -1;
            edges[i] = new ArrayList<>();
        }
        for (int i = 0; i < m; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            edges[u].add(v);
        }
        for (int i = 0; i < n; i++) {
            if (num[i] == -1) dfs(i);
        }
        System.out.println(scc);
    }
}

