const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', function(line) {
    input.push(line);
}).on('close', function() {
    let [n, m] = input[0].split(' ').map(x => parseInt(x));
    let low = new Array(n).fill(0);
    let num = new Array(n).fill(-1);
    let stack = new Array(n).fill(0);
    let edges = new Array(n).fill(0).map(() => []);
    let scc = 0;
    let idx = 0;
    function dfs(u) {
        let stackSize = 0;
        num[u] = low[u] = idx;
        idx++;
        stack[stackSize] = u;
        stackSize++;
        for (let v of edges[u]) {
            if (num[v] == -1) {
                dfs(v);
                low[u] = Math.min(low[u], low[v]);
            } else if (stack[stackSize - 1] != v) {
                low[u] = Math.min(low[u], num[v]);
            }
        }
        if (low[u] == num[u]) {
            while (true) {
                let v = stack[stackSize - 1];
                stackSize--;
                if (v == u) break;
            }
